CREATE TABLE farmers_india (
    id INT PRIMARY KEY,
    name VARCHAR(255),
    district_id INT,
    age INT,
    income INT,
    FOREIGN KEY (district_id) REFERENCES districts_india(id)
);

CREATE TABLE districts_india (
    id INT PRIMARY KEY,
    name VARCHAR(255),
    state VARCHAR(255)
);

CREATE TABLE startups (
    id INT PRIMARY KEY,
    name VARCHAR(50),
    domain VARCHAR(50),
    location VARCHAR(50)
);

CREATE TABLE funding (
    id INT PRIMARY KEY,
    startup_id INT,
    amount DECIMAL(10, 2),
    purpose VARCHAR(50),
    FOREIGN KEY (startup_id) REFERENCES startups(id)
);

CREATE TABLE HumanitarianAssistance (
    Country VARCHAR(50),
    Organization VARCHAR(50),
    Amount INT,
    Year INT
);

CREATE TABLE NGOs (
    Organization VARCHAR(50) PRIMARY KEY
);

CREATE TABLE AfricanCountries (
    Country VARCHAR(50) PRIMARY KEY
);

CREATE TABLE GovernmentMilitaryOrganizations (
    Organization VARCHAR(50) PRIMARY KEY
);
